concept.codeExample:
const backends = [
  { url: 'http://10.0.0.1:8080', active: 0 },
  { url: 'http://10.0.0.2:8080', active: 0 },
  { url: 'http://10.0.0.3:8080', active: 0 }
];

function pickP2C() {
  const n = backends.length;
  if (n === 0) throw new Error('no backends');
  const a = Math.floor(Math.random() * n);
  let b = Math.floor(Math.random() * n);
  while (b === a && n > 1) b = Math.floor(Math.random() * n);
  return backends[ backends[a].active <= backends[b].active ? a : b ];
}

